const book: BibleBook = {
  id: 'ruth',
  name: 'Rute',
  englishName: 'Ruth',
  testament: 'old',
  chapters: {
    1: [
      { v: 1, en: 'In the days when the judges judged, there was a famine in the land. A certain man of Bethlehem Judah went to live in the country of Moab, he, and his wife, and his two sons.', pt: 'Nos dias em que os juízes governavam, houve uma fome na terra; pelo que um homem de Belém de Judá saiu a peregrinar no país de Moabe, ele, sua mulher, e seus dois filhos.' },
      { v: 2, en: 'The name of the man was Elimelech, and the name of his wife Naomi. The names of his two sons were Mahlon and Chilion, Ephrathites of Bethlehem Judah. They came into the country of Moab, and lived there.', pt: 'Chamava-se este homem Elimeleque, e sua mulher Noêmi, e seus dois filhos se chamavam Malom e Quiliom; eram efrateus, de Belém de Judá. Tendo entrado no país de Moabe, ficaram ali.' },
      { v: 3, en: 'Elimelech, Naomi’s husband, died; and she was left with her two sons.', pt: 'E morreu Elimeleque, marido de Noêmi; e ficou ela com os seus dois filhos,' },
      { v: 4, en: 'They took for themselves wives of the women of Moab. The name of the one was Orpah, and the name of the other was Ruth. They lived there about ten years.', pt: 'os quais se casaram com mulheres moabitas; uma destas se chamava Orfa, e a outra Rute; e moraram ali quase dez anos.' },
      { v: 5, en: 'Mahlon and Chilion both died, and the woman was bereaved of her two children and of her husband.', pt: 'E morreram também os dois, Malom e Quiliom, ficando assim a mulher desamparada de seus dois filhos e de seu marido.' },
      { v: 6, en: 'Then she arose with her daughters-in-law, that she might return from the country of Moab; for she had heard in the country of Moab how Yahweh had visited his people in giving them bread.', pt: 'Então se levantou ela com as suas noras, para voltar do país de Moabe, porquanto nessa terra tinha ouvido que e Senhor havia visitado o seu povo, dando-lhe pão.' },
      { v: 7, en: 'She went out of the place where she was, and her two daughters-in-law with her. They went on the way to return to the land of Judah.', pt: 'Pelo que saiu de lugar onde estava, e com ela as duas noras. Indo elas caminhando para voltarem para a terra de Judá,' },
      { v: 8, en: 'Naomi said to her two daughters-in-law, “Go, return each of you to her mother’s house. May Yahweh deal kindly with you, as you have dealt with the dead, and with me.', pt: 'disse Noêmi às suas noras: Ide, voltai, cada uma para a casa de sua mãe; e o Senhor use convosco de benevolência, como vós o fizestes com os falecidos e comigo.' },
      { v: 9, en: 'May Yahweh grant you that you may find rest, each of you in the house of her husband.” Then she kissed them, and they lifted up their voices, and wept.', pt: 'O Senhor vos dê que acheis descanso cada uma em casa de seu marido. Quando as beijou, porém, levantaram a vóz e choraram.' },
      { v: 10, en: 'They said to her, “No, but we will return with you to your people.”', pt: 'E disseram-lhe: Certamente voltaremos contigo para o teu povo.' },
      { v: 11, en: 'Naomi said, “Go back, my daughters. Why do you want to go with me? Do I still have sons in my womb, that they may be your husbands?', pt: 'Noêmi, porém, respondeu: Voltai, minhas filhas; porque ireis comigo? Tenho eu ainda filhos no meu ventre, para que vos viessem a ser maridos?' },
      { v: 12, en: 'Go back, my daughters, go your way; for I am too old to have a husband. If I should say, ‘I have hope,’ if I should even have a husband tonight, and should also bear sons;', pt: 'Voltai, filhas minhas; ide-vos, porque já sou velha demais para me casar. Ainda quando eu dissesse: Tenho esperança; ainda que esta noite tivesse marido e ainda viesse a ter filhos.' },
      { v: 13, en: 'would you then wait until they were grown? Would you then refrain from having husbands? No, my daughters, for it grieves me seriously for your sakes, for Yahweh’s hand has gone out against me.”', pt: 'esperá-los-íeis até que viessem a ser grandes? deter-vos-íeis por eles, sem tomardes marido? Não, filhas minhas, porque mais amargo me é a mim do que a vós mesmas; porquanto a mão do Senhor se descarregou contra mim.' },
      { v: 14, en: 'They lifted up their voices, and wept again; then Orpah kissed her mother-in-law, but Ruth joined with her.', pt: 'Então levantaram a voz, e tornaram a chorar; e Orfa beijou a sua sogra, porém Rute se apegou a ela.' },
      { v: 15, en: 'She said, “Behold, your sister-in-law has gone back to her people, and to her god. Follow your sister-in-law.”', pt: 'Pelo que disse Noêmi: Eis que tua concunhada voltou para o seu povo e para os seus deuses; volta também tu após a tua concunhada.' },
      { v: 16, en: 'Ruth said, “Don’t urge me to leave you, and to return from following you, for where you go, I will go; and where you stay, I will stay. Your people will be my people, and your God my God.', pt: 'Respondeu, porém, Rute: Não me instes a que te abandone e deixe de seguir-te. Porque aonde quer que tu fores, irei eu; e onde quer que pousares, ali pousarei eu; o teu povo será o meu povo, o teu Deus será o meu Deus.' },
      { v: 17, en: 'Where you die, I will die, and there I will be buried. May Yahweh do so to me, and more also, if anything but death parts you and me.”', pt: 'Onde quer que morreres, morrerei eu, e ali serei sepultada. Assim me faça o Senhor, e outro tanto, se outra coisa que não seja a morte me separar de ti.' },
      { v: 18, en: 'When she saw that she was determined to go with her, she stopped urging her.', pt: 'Vendo Noêmi que de todo estava resolvida a ir com ela, deixou de lhe falar nisso.' },
      { v: 19, en: 'So they both went until they came to Bethlehem. When they had come to Bethlehem, all the city was excited about them, and they asked, “Is this Naomi?”', pt: 'Assim, pois, foram-se ambas, até que chegaram a Belém. E sucedeu que, ao entrarem em Belém, toda a cidade se comoveu por causa delas, e as mulheres perguntavam: É esta, porventura, Noêmi?' },
      { v: 20, en: 'She said to them, “Don’t call me Naomi. Call me Mara; for the Almighty has dealt very bitterly with me.', pt: 'Ela, porém, lhes respondeu: Não me chameis Noêmi; chamai-me Mara, porque o Todo-Poderoso me encheu de amargura.' },
      { v: 21, en: 'I went out full, and Yahweh has brought me home again empty. Why do you call me Naomi, since Yahweh has testified against me, and the Almighty has afflicted me?”', pt: 'Cheia parti, porém vazia o Senhor me fez tornar. Por que, pois, me chamais Noêmi, visto que o Senhor testemunhou contra mim, e o Todo-Poderoso me afligiu?' },
      { v: 22, en: 'So Naomi returned, and Ruth the Moabitess, her daughter-in-law, with her, who returned out of the country of Moab. They came to Bethlehem in the beginning of barley harvest.', pt: 'Assim Noêmi voltou, e com ela Rute, a moabita, sua nora, que veio do país de Moabe; e chegaram a Belém no principio da sega da cevada.' },
    ],
    2: [
      { v: 1, en: 'Naomi had a relative of her husband’s, a mighty man of wealth, of the family of Elimelech, and his name was Boaz.', pt: 'Ora, tinha Noêmi um parente de seu marido, homem poderoso e rico, da família de Elimeleque; e ele se chamava Boaz.' },
      { v: 2, en: 'Ruth the Moabitess said to Naomi, “Let me now go to the field, and glean among the ears of grain after him in whose sight I find favor.” She said to her, “Go, my daughter.”', pt: 'Rute, a moabita, disse a Noêmi: Deixa-me ir ao campo a apanhar espigas atrás daquele a cujos olhos eu achar graça. E ela lhe respondeu: Vai, minha filha.' },
      { v: 3, en: 'She went, and came and gleaned in the field after the reapers; and she happened to come to the portion of the field belonging to Boaz, who was of the family of Elimelech.', pt: 'Foi, pois, e chegando ao campo respigava após os segadores; e caiu-lhe em sorte uma parte do campo de Boaz, que era da família de Elimeleque.' },
      { v: 4, en: 'Behold, Boaz came from Bethlehem, and said to the reapers, “May Yahweh be with you.” They answered him, “May Yahweh bless you.”', pt: 'E eis que Boaz veio de Belém, e disse aos segadores: O Senhor seja convosco. Responderam-lhe eles: O Senhor te abençoe.' },
      { v: 5, en: 'Then Boaz said to his servant who was set over the reapers, “Whose young lady is this?”', pt: 'Depois perguntou Boaz ao moço que estava posto sobre os segadores: De quem é esta moça?' },
      { v: 6, en: 'The servant who was set over the reapers answered, “It is the Moabite lady who came back with Naomi out of the country of Moab.', pt: 'Respondeu-lhe o moço: Esta é a moça moabita que voltou com Noêmi do país de Moabe.' },
      { v: 7, en: 'She said, ‘Please let me glean and gather after the reapers among the sheaves.’ So she came, and has continued even from the morning until now, except that she rested a little in the house.”', pt: 'Disse-me ela: Deixa-me colher e ajuntar espigas por entre os molhos após os segadores: Assim ela veio, e está aqui desde pela manhã até agora, sem descansar nem sequer um pouco.' },
      { v: 8, en: 'Then Boaz said to Ruth, “Listen, my daughter. Don’t go to glean in another field, and don’t go from here, but stay here close to my maidens.', pt: 'Então disse Boaz a Rute: Escuta filha minha; não vás colher em outro campo, nem tampouco passes daqui, mas ajunta-te às minhas moças.' },
      { v: 9, en: 'Let your eyes be on the field that they reap, and go after them. Haven’t I commanded the young men not to touch you? When you are thirsty, go to the vessels, and drink from that which the young men have drawn.”', pt: 'Os teus olhos estarão atentos no campo que segarem, e irás após elas; não dei eu ordem aos moços, que não te molestem? Quando tiveres sede, vai aos vasos, e bebe do que os moços tiverem tirado.' },
      { v: 10, en: 'Then she fell on her face, and bowed herself to the ground, and said to him, “Why have I found favor in your sight, that you should take knowledge of me, since I am a foreigner?”', pt: 'Então ela, inclinando-se e prostrando-se com o rosto em terra, perguntou-lhe: Por que achei eu graça aos teus olhos, para que faças caso de mim, sendo eu estrangeira?' },
      { v: 11, en: 'Boaz answered her, “I have been told all about what you have done for your mother-in-law since the death of your husband, and how you have left your father and your mother, and the land of your birth, and have come to a people that you didn’t know before.', pt: 'Ao que lhe respondeu Boaz: Bem se me contou tudo quanto tens feito para com tua sogra depois da morte de teu marido; como deixaste a teu pai e a tua mãe, e a terra onde nasceste, e vieste para um povo que dantes não conhecias.' },
      { v: 12, en: 'May Yahweh repay your work, and a full reward be given to you from Yahweh, the God of Israel, under whose wings you have come to take refuge.”', pt: 'O Senhor recompense o que fizeste, e te seja concedido pleno galardão da parte do Senhor Deus de Israel, sob cujas asas te vieste abrigar.' },
      { v: 13, en: 'Then she said, “Let me find favor in your sight, my lord, because you have comforted me, and because you have spoken kindly to your servant, though I am not as one of your servants.”', pt: 'E disse ela: Ache eu graça aos teus olhos, senhor meu, pois me consolaste, e falaste bondosamente a tua serva, não sendo eu nem mesmo como uma das tuas criadas.' },
      { v: 14, en: 'At meal time Boaz said to her, “Come here, and eat some bread, and dip your morsel in the vinegar.” She sat beside the reapers, and they passed her parched grain, and she ate, and was satisfied, and left some of it.', pt: 'Também à hora de comer, disse-lhe Boaz: Achega-te, come do pão e molha o teu bocado no vinagre. E, sentando-se ela ao lado dos segadores, ele lhe ofereceu grão tostado, e ela comeu e ficou satisfeita, e ainda lhe sobejou.' },
      { v: 15, en: 'When she had risen up to glean, Boaz commanded his young men, saying, “Let her glean even among the sheaves, and don’t reproach her.', pt: 'Quando ela se levantou para respigar, Boaz deu ordem aos seus moços, dizendo: Até entre os molhos deixai-a respirar, e não a censureis.' },
      { v: 16, en: 'Also pull out some for her from the bundles, and leave it. Let her glean, and don’t rebuke her.”', pt: 'Também, tirai dos molhos algumas espigas e deixai-as ficar, para que as colha, e não a repreendais.' },
      { v: 17, en: 'So she gleaned in the field until evening; and she beat out that which she had gleaned, and it was about an ephah of barley.', pt: 'Assim ela respigou naquele campo até a tarde; e debulhou o que havia apanhado e foi quase uma efa de cevada.' },
      { v: 18, en: 'She took it up, and went into the city. Then her mother-in-law saw what she had gleaned; and she brought out and gave to her that which she had left after she had enough.', pt: 'Então, carregando com a cevada, veio à cidade; e viu sua sogra o que ela havia apanhado. Também Rute tirou e deu-lhe o que lhe sobejara depois de fartar-se.' },
      { v: 19, en: 'Her mother-in-law said to her, “Where have you gleaned today? Where have you worked? Blessed be he who noticed you.” She told her mother-in-law with whom she had worked, “The man’s name with whom I worked today is Boaz.”', pt: 'Ao que lhe perguntou sua sogra: Onde respigaste hoje, e onde trabalhaste? Bendito seja aquele que fez caso de ti. E ela relatou à sua sogra com quem tinha trabalhado, e disse: O nome do homem com quem hoje trabalhei é Boaz.' },
      { v: 20, en: 'Naomi said to her daughter-in-law, “May he be blessed by Yahweh, who has not abandoned his kindness to the living and to the dead.” Naomi said to her, “The man is a close relative to us, one of our near kinsmen.”', pt: 'Disse Noêmi a sua nora: Bendito seja ele do Senhor, que não tem deixado de misturar a sua beneficência nem para com os vivos nem para com os mortos. Disse-lhe mais Noêmi: Esse homem é parente nosso, um dos nossos remidores.' },
      { v: 21, en: 'Ruth the Moabitess said, “Yes, he said to me, ‘You shall stay close to my young men, until they have finished all my harvest.’”', pt: 'Respondeu Rute, a moabita: Ele me disse ainda: Seguirás de perto os meus moços até que tenham acabado toda a minha sega.' },
      { v: 22, en: 'Naomi said to Ruth her daughter-in-law, “It is good, my daughter, that you go out with his maidens, and that they not meet you in any other field.”', pt: 'Então disse Noêmi a sua nora, Rute: Bom é, filha minha, que saias com as suas moças, e que não te encontrem noutro campo.' },
      { v: 23, en: 'So she stayed close to the maidens of Boaz, to glean to the end of barley harvest and of wheat harvest; and she lived with her mother-in-law.', pt: 'Assim se ajuntou com as moças de Boaz, para respigar até e fim da sega da cevada e do trigo; e morava com a sua sogra.' },
    ],
    3: [
      { v: 1, en: 'Naomi her mother-in-law said to her, “My daughter, shall I not seek rest for you, that it may be well with you?', pt: 'Depois lhe disse Noêmi, sua sogra: Minha filha, não te hei de buscar descanso, para que fiques bem?' },
      { v: 2, en: 'Now isn’t Boaz our kinsman, with whose maidens you were? Behold, he will be winnowing barley tonight on the threshing floor.', pt: 'Ora pois, não é Boaz, com cujas moças estiveste, de nossa parentela. Eis que esta noite ele vai joeirar a cevada na eira.' },
      { v: 3, en: 'Therefore wash yourself, anoint yourself, get dressed, and go down to the threshing floor, but don’t make yourself known to the man until he has finished eating and drinking.', pt: 'Lava-te pois, unge-te, veste os teus melhores vestidos, e desce à eira; porém não te dês a conhecer ao homem, até que tenha acabado de comer e beber.' },
      { v: 4, en: 'It shall be, when he lies down, that you shall note the place where he is lying. Then you shall go in, uncover his feet, and lay down. Then he will tell you what to do.”', pt: 'E quando ele se deitar, notarás o lugar em que se deita; então entrarás, descobrir-lhe-ás os pés e te deitarás, e ele te dirá o que deves fazer.' },
      { v: 5, en: 'She said to her, “All that you say, I will do.”', pt: 'Respondeu-lhe Rute: Tudo quanto me disseres, farei.' },
      { v: 6, en: 'She went down to the threshing floor, and did everything that her mother-in-law told her.', pt: 'Então desceu à eira, e fez conforme tudo o que sua sogra lhe tinha ordenado.' },
      { v: 7, en: 'When Boaz had eaten and drunk, and his heart was merry, he went to lie down at the end of the heap of grain. She came softly, uncovered his feet, and laid down.', pt: 'Havendo, pois, Boaz comido e bebido, e estando já o seu coração alegre, veio deitar-se ao pé de uma meda; e vindo ela de mansinho, descobriu-lhe os pés, e se deitou.' },
      { v: 8, en: 'At midnight, the man was startled and turned himself; and behold, a woman lay at his feet.', pt: 'Ora, pela meia-noite, o homem estremeceu, voltou-se, e viu uma mulher deitada aos seus pes.' },
      { v: 9, en: 'He said, “Who are you?” She answered, “I am Ruth your servant. Therefore spread the corner of your garment over your servant; for you are a near kinsman.”', pt: 'E perguntou ele: Quem és tu? Ao que ela respondeu: Sou Rute, tua serva; estende a tua capa sobre a tua serva, porque tu és o remidor.' },
      { v: 10, en: 'He said, “You are blessed by Yahweh, my daughter. You have shown more kindness in the latter end than at the beginning, because you didn’t follow young men, whether poor or rich.', pt: 'Então disse ele: Bendita sejas tu do Senhor, minha filha; mostraste agora mais bondade do que dantes, visto que após nenhum mancebo foste, quer pobre quer rico.' },
      { v: 11, en: 'Now, my daughter, don’t be afraid. I will do to you all that you say; for all the city of my people knows that you are a worthy woman.', pt: 'Agora, pois, minha filha, não temas; tudo quanto disseres te farei, pois toda a cidade do meu povo sabe que és mulher virtuosa.' },
      { v: 12, en: 'Now it is true that I am a near kinsman. However, there is a kinsman nearer than I.', pt: 'Ora, é bem verdade que eu sou remidor, porém há ainda outro mais chegado do que eu.' },
      { v: 13, en: 'Stay this night, and in the morning, if he will perform for you the part of a kinsman, good. Let him do the kinsman’s duty. But if he will not do the duty of a kinsman for you, then I will do the duty of a kinsman for you, as Yahweh lives. Lie down until the morning.”', pt: 'Fica-te aqui esta noite, e será que pela manhã, se ele cumprir para contigo os deveres de remidor, que o faça; mas se não os quiser cumprir, então eu o farei tão certamente como vive o Senhor; deita-te até pela manhã.' },
      { v: 14, en: 'She lay at his feet until the morning, then she rose up before one could discern another. For he said, “Let it not be known that the woman came to the threshing floor.”', pt: 'Ficou, pois, deitada a seus pés até pela manhã, e levantou-se antes que fosse possível a uma pessoa reconhecer outra; porquanto ele disse: Não se saiba que uma mulher veio à eira.' },
      { v: 15, en: 'He said, “Bring the mantle that is on you, and hold it.” She held it; and he measured six measures of barley, and laid it on her; then he went into the city.', pt: 'Disse mais: Traze aqui a capa com que te cobres, e segura-a. Segurou-a, pois, e ele as mediu seis medidas de cevada, e lhas pôs no ombro. Então ela foi para a cidade.' },
      { v: 16, en: 'When she came to her mother-in-law, she said, “How did it go, my daughter?” She told her all that the man had done for her.', pt: 'Quando chegou à sua sogra, esta lhe perguntou: Como te houveste, minha filha? E ela lhe contou tudo quanto aquele homem lhe fizera.' },
      { v: 17, en: 'She said, “He gave me these six measures of barley; for he said, ‘Don’t go empty to your mother-in-law.’”', pt: 'Disse mais: Estas seis medidas de cevada ele mas deu, dizendo: Não voltarás vazia para tua sogra.' },
      { v: 18, en: 'Then she said, “Wait, my daughter, until you know what will happen; for the man will not rest until he has settled this today.”', pt: 'Então disse Noêmi: Espera, minha filha, até que saibas como irá terminar o caso; porque aquele homem não descansará enquanto não tiver concluído hoje este negócio.' },
    ],
    4: [
      { v: 1, en: 'Now Boaz went up to the gate, and sat down there. Behold, the near kinsman of whom Boaz spoke came by. He said to him, “Come over here, friend, and sit down!” He came over, and sat down.', pt: 'Boaz subiu à porta, e sentou-se ali; e eis que o remidor de quem ar de jumentos. Ela o levou à casa de seu pai, o qual, vendo-o, ele, desviando-se para ali, sentou-se.' },
      { v: 2, en: 'He took ten men of the elders of the city, and said, “Sit down here,” and they sat down.', pt: 'Então Boaz tomou dez homens dentre os anciãos da cidade, e lhes disse: Sentai-vos aqui. E eles se sentaram.' },
      { v: 3, en: 'He said to the near kinsman, “Naomi, who has come back out of the country of Moab, is selling the parcel of land, which was our brother Elimelech’s.', pt: 'Disse Boaz ao remidor: Noêmi, que voltou da terra dos moabitas, vendeu a parte da terra que pertencia a Elimeleque; nosso irmão.' },
      { v: 4, en: 'I thought I should tell you, saying, ‘Buy it before those who sit here, and before the elders of my people.’ If you will redeem it, redeem it; but if you will not redeem it, then tell me, that I may know. For there is no one to redeem it besides you; and I am after you.” He said, “I will redeem it.”', pt: 'Resolvi informar-te disto, e dizer-te: Compra-a na presença dos que estão sentados aqui, na presença dos anciãos do meu povo; se hás de redimi-la, redime-a, e se não, declara-mo, para que o saiba, pois outro não há, senão tu, que a redima, e eu depois de ti. Então disse ele: Eu a redimirei.' },
      { v: 5, en: 'Then Boaz said, “On the day you buy the field from the hand of Naomi, you must buy it also from Ruth the Moabitess, the wife of the dead, to raise up the name of the dead on his inheritance.”', pt: 'Disse, porém, Boaz: No dia em que comprares o campo da mão de Noêmi, também tomarás a Rute, a moabita, que foi mulher do falecido, para suscitar o nome dele na sua herança.' },
      { v: 6, en: 'The near kinsman said, “I can’t redeem it for myself, lest I endanger my own inheritance. Take my right of redemption for yourself; for I can’t redeem it.”', pt: 'Então disse o remidor: Não poderei redimi-lo para mim, para que não prejudique a minha própria herança; toma para ti o meu direito de remissão, porque eu não o posso fazer.' },
      { v: 7, en: 'Now this was the custom in former time in Israel concerning redeeming and concerning exchanging, to confirm all things: a man took off his shoe, and gave it to his neighbor; and this was the way of formalizing transactions in Israel.', pt: 'Outrora em Israel, para confirmar qualquer negócio relativo à remissão e à permuta, o homem descalçava o sapato e o dava ao seu próximo; e isto era por testemunho em Israel.' },
      { v: 8, en: 'So the near kinsman said to Boaz, “Buy it for yourself,” then he took off his shoe.', pt: 'Dizendo, pois, o remidor a Boaz: Compra-a para ti, descalçou o sapato.' },
      { v: 9, en: 'Boaz said to the elders, and to all the people, “You are witnesses today, that I have bought all that was Elimelech’s, and all that was Chilion’s and Mahlon’s, from the hand of Naomi.', pt: 'Então Boaz disse aos anciãos e a todo o povo: Sois hoje testemunhas de que comprei tudo quanto foi de Elimeleque, e de Quiliom, e de Malom, da mão de Noêmi,' },
      { v: 10, en: 'Moreover Ruth the Moabitess, the wife of Mahlon, I have purchased to be my wife, to raise up the name of the dead on his inheritance, that the name of the dead may not be cut off from among his brothers, and from the gate of his place. You are witnesses today.”', pt: 'e de que também tomei por mulher a Rute, a moabita, que foi mulher de Malom, para suscitar o nome do falecido na sua herança, para que a nome dele não seja desarraigado dentre seus irmãos e da porta do seu lugar; disto sois hoje testemunhas.' },
      { v: 11, en: 'All the people who were in the gate, and the elders, said, “We are witnesses. May Yahweh make the woman who has come into your house like Rachel and like Leah, which both built the house of Israel; and treat you worthily in Ephrathah, and be famous in Bethlehem.', pt: 'Ao que todo o povo que estava na porta e os anciãos responderam: Somos testemunhas. O Senhor faça a esta mulher, que entra na tua casa, como a Raquel e a Léia, que juntas edificaram a casa de Israel. Porta-te valorosamente em Efrata, e faze-te nome afamado em Belém.' },
      { v: 12, en: 'Let your house be like the house of Perez, whom Tamar bore to Judah, of the offspring which Yahweh will give you by this young woman.”', pt: 'Também seja a tua casa como a casa de Pérez, que Tamar deu a Judá, pela posteridade que o Senhor te der desta moça.' },
      { v: 13, en: 'So Boaz took Ruth, and she became his wife; and he went in to her, and Yahweh enabled her to conceive, and she bore a son.', pt: 'Assim tomou Boaz a Rute, e ela lhe foi por mulher; ele a conheceu, e o Senhor permitiu a Rute conceber, e ela teve um filho.' },
      { v: 14, en: 'The women said to Naomi, “Blessed be Yahweh, who has not left you today without a near kinsman. Let his name be famous in Israel.', pt: 'Disseram então as mulheres a Noêmi: Bendito seja o Senhor, que não te deixou hoje sem remidor; e torne-se o seu nome afamado em Israel.' },
      { v: 15, en: 'He shall be to you a restorer of life, and sustain you in your old age, for your daughter-in-law, who loves you, who is better to you than seven sons, has given birth to him.”', pt: 'Ele será restaurador da tua vida, e consolador da tua velhice, pois tua nora, que te ama, o deu à luz; ela te é melhor do que sete filhos.' },
      { v: 16, en: 'Naomi took the child, and laid him in her bosom, and became nurse to it.', pt: 'E Noêmi tomou o menino, pô-lo no seu regaço, e foi sua ama.' },
      { v: 17, en: 'The women, her neighbors, gave him a name, saying, “A son is born to Naomi”. They named him Obed. He is the father of Jesse, the father of David.', pt: 'E as vizinhas deram-lhe nome, dizendo: A Noêmi nasceu um filho, E chamaram ao menino Obede. Este é o pai de Jessé, pai de Davi.' },
      { v: 18, en: 'Now this is the history of the generations of Perez: Perez became the father of Hezron,', pt: 'São estas as gerações de Pérez: Pérez gerou a Hezrom,' },
      { v: 19, en: 'and Hezron became the father of Ram, and Ram became the father of Amminadab,', pt: 'Hezrom gerou a Rão, Rão gerou a Aminadabe,' },
      { v: 20, en: 'and Amminadab became the father of Nahshon, and Nahshon became the father of Salmon,', pt: 'Aminadabe gereu a Nasom, Nasom gerou a Salmom,' },
      { v: 21, en: 'and Salmon became the father of Boaz, and Boaz became the father of Obed,', pt: 'Salmom gerou a Boaz, Boaz gerou a Obede,' },
      { v: 22, en: 'and Obed became the father of Jesse, and Jesse became the father of David.', pt: 'Obede gerou a Jessé, e Jessé gerou a Davi.' },
    ],
  },
};

export default book;
